def _databricks_dashboard_to_nested(databricks_dashboard: DatabricksDashboard) -> DatabricksDashboardNested:
    """Convert flat DatabricksDashboard to nested format."""
    attrs = DatabricksDashboardAttributes()
    _populate_databricks_dashboard_attrs(attrs, databricks_dashboard)
    # Categorize relationships by save semantic (REPLACE, APPEND, REMOVE)
    replace_rels, append_rels, remove_rels = categorize_relationships(
        databricks_dashboard, _DATABRICKS_DASHBOARD_REL_FIELDS, DatabricksDashboardRelationshipAttributes
    )
    return DatabricksDashboardNested(
        guid=databricks_dashboard.guid,
        type_name=databricks_dashboard.type_name,
        status=databricks_dashboard.status,
        version=databricks_dashboard.version,
        create_time=databricks_dashboard.create_time,
        update_time=databricks_dashboard.update_time,
        created_by=databricks_dashboard.created_by,
        updated_by=databricks_dashboard.updated_by,
        classifications=databricks_dashboard.classifications,
        classification_names=databricks_dashboard.classification_names,
        meanings=databricks_dashboard.meanings,
        labels=databricks_dashboard.labels,
        business_attributes=databricks_dashboard.business_attributes,
        custom_attributes=databricks_dashboard.custom_attributes,
        pending_tasks=databricks_dashboard.pending_tasks,
        proxy=databricks_dashboard.proxy,
        is_incomplete=databricks_dashboard.is_incomplete,
        provenance_type=databricks_dashboard.provenance_type,
        home_id=databricks_dashboard.home_id,
        attributes=attrs,
        relationship_attributes=replace_rels,
        append_relationship_attributes=append_rels,
        remove_relationship_attributes=remove_rels,
    )

def _databricks_dashboard_from_nested(nested: DatabricksDashboardNested) -> DatabricksDashboard:
    """Convert nested format to flat DatabricksDashboard."""
    attrs = nested.attributes if nested.attributes is not UNSET else DatabricksDashboardAttributes()
    # Merge relationships from all three buckets
    merged_rels = merge_relationships(
        nested.relationship_attributes,
        nested.append_relationship_attributes,
        nested.remove_relationship_attributes,
        _DATABRICKS_DASHBOARD_REL_FIELDS,
        DatabricksDashboardRelationshipAttributes
    )
    return DatabricksDashboard(
        guid=nested.guid,
        type_name=nested.type_name,
        status=nested.status,
        version=nested.version,
        create_time=nested.create_time,
        update_time=nested.update_time,
        created_by=nested.created_by,
        updated_by=nested.updated_by,
        classifications=nested.classifications,
        classification_names=nested.classification_names,
        meanings=nested.meanings,
        labels=nested.labels,
        business_attributes=nested.business_attributes,
        custom_attributes=nested.custom_attributes,
        pending_tasks=nested.pending_tasks,
        proxy=nested.proxy,
        is_incomplete=nested.is_incomplete,
        provenance_type=nested.provenance_type,
        home_id=nested.home_id,
        **_extract_databricks_dashboard_attrs(attrs),
        # Merged relationship attributes
        **merged_rels,
    )

def _databricks_dashboard_to_nested_bytes(databricks_dashboard: DatabricksDashboard, serde: Serde) -> bytes:
    """Convert flat DatabricksDashboard to nested JSON bytes."""
    return serde.encode(_databricks_dashboard_to_nested(databricks_dashboard))


def _databricks_dashboard_from_nested_bytes(data: bytes, serde: Serde) -> DatabricksDashboard:
    """Convert nested JSON bytes to flat DatabricksDashboard."""
    nested = serde.decode(data, DatabricksDashboardNested)
    return _databricks_dashboard_from_nested(nested)

